            return 0 <= i < len(num) and 0 <= j < len(num) and (num[i:i+len(str(int(num[i:j]))) ] == str(int(num[i:j])))

        def backtrack(index, prev1, prev2):
            if index == len(num):
                return True
            if prev1 + prev2 > 2**31 - 1 or prev1 + prev2 < 0:
                return False
            for i in range(index + 1, len(num) + 1):
                if is_valid_split(index, i):
                    curr = int(num[index:i])
                    if backtrack(i, prev2, prev1 + prev2):
                        return True
            return False

        if backtrack(0, 0, 0):
            return [0, 0]
        return []
